+                && !e.file_name().to_string_lossy().contains(".scrub.")
+                && !e.file_name().to_string_lossy().contains(".proof.")
+        })
+        .collect();
+
+    let mut pass_count = 0_usize;
+    let mut fail_count = 0_usize;
