+            "total": entries.len(),
+            "passed": pass_count,
+            "failed": fail_count,
+            "missing_sidecar": missing_count,
+            "results": results,
+        });
+        println!("{}", serde_json::to_string_pretty(&report).unwrap());
+    } else {
+        println!(
+            "verify: {} artifacts, {} passed, {} failed, {} missing sidecar",
+            entries.len(),
+            pass_count,
+            fail_count,
+            missing_count
+        );
